### 2) Metric Computation Functions
```rust
/// Compute NDCG@K (Normalized Discounted Cumulative Gain)
pub fn ndcg_at_k(ranked_relevances: &[f64], k: usize) -> f64 {
    let dcg: f64 = ranked_relevances.iter()
        .take(k)
        .enumerate()
        .map(|(i, &rel)| (2f64.powf(rel) - 1.0) / (i as f64 + 2.0).log2())
        .sum();

    // Ideal DCG: sort relevances descending
    let mut ideal = ranked_relevances.to_vec();
    ideal.sort_by(|a, b| b.partial_cmp(a).unwrap_or(std::cmp::Ordering::Equal));
    let idcg: f64 = ideal.iter()
        .take(k)
        .enumerate()
        .map(|(i, &rel)| (2f64.powf(rel) - 1.0) / (i as f64 + 2.0).log2())
        .sum();

    if idcg == 0.0 { 0.0 } else { dcg / idcg }
}

/// Compute MRR (Mean Reciprocal Rank)
pub fn mrr(ranked_relevances: &[f64], threshold: f64) -> f64 {
    for (i, &rel) in ranked_relevances.iter().enumerate() {
        if rel >= threshold {
            return 1.0 / (i as f64 + 1.0);
        }
    }
    0.0
}

/// Compute MAP@K (Mean Average Precision)
pub fn map_at_k(ranked_relevances: &[f64], k: usize, threshold: f64) -> f64 {
    let mut sum_precision = 0.0;
    let mut relevant_count = 0;

    for (i, &rel) in ranked_relevances.iter().take(k).enumerate() {
        if rel >= threshold {
            relevant_count += 1;
            sum_precision += relevant_count as f64 / (i as f64 + 1.0);
        }
    }

    let total_relevant = ranked_relevances.iter().filter(|&&r| r >= threshold).count();
    if total_relevant == 0 { 0.0 } else { sum_precision / total_relevant as f64 }
}

/// Compute percentile from sorted latency measurements
pub fn percentile(values: &[Duration], p: f64) -> f64 {
    assert!(!values.is_empty());
    assert!((0.0..=1.0).contains(&p));
    let mut sorted: Vec<f64> = values.iter().map(|d| d.as_secs_f64() * 1000.0).collect();
    sorted.sort_by(|a, b| a.partial_cmp(b).unwrap());
    let idx = ((sorted.len() - 1) as f64 * p).round() as usize;
    sorted[idx]
}

/// Coefficient of variation (jitter measure)
pub fn coefficient_of_variation(values: &[Duration]) -> f64 {
    let ms: Vec<f64> = values.iter().map(|d| d.as_secs_f64() * 1000.0).collect();
    let mean = ms.iter().sum::<f64>() / ms.len() as f64;
    if mean == 0.0 { return 0.0; }
    let variance = ms.iter().map(|x| (x - mean).powi(2)).sum::<f64>() / ms.len() as f64;
    variance.sqrt() / mean
}

/// Bootstrap confidence interval (used by bd-2ep for significance testing)
pub fn bootstrap_ci(
    values: &[f64],
    n_bootstrap: usize,
    confidence: f64,
) -> (f64, f64) {
    let mut rng = SmallRng::seed_from_u64(42);  // Deterministic for reproducibility
    let n = values.len();
    let mut means = Vec::with_capacity(n_bootstrap);

    for _ in 0..n_bootstrap {
        let sample_mean: f64 = (0..n)
            .map(|_| values[rng.gen_range(0..n)])
            .sum::<f64>() / n as f64;
        means.push(sample_mean);
    }

    means.sort_by(|a, b| a.partial_cmp(b).unwrap());
    let alpha = (1.0 - confidence) / 2.0;
    let lo_idx = (alpha * means.len() as f64).floor() as usize;
    let hi_idx = ((1.0 - alpha) * means.len() as f64).ceil() as usize;
    (means[lo_idx], means[hi_idx.min(means.len() - 1)])
}
