#[test]
fn test_ndcg_perfect_ranking() {
    // Perfect ranking: all relevant docs at top
    let rels = vec![2.0, 2.0, 1.0, 0.0, 0.0];
    assert!((ndcg_at_k(&rels, 5) - 1.0).abs() < 1e-10);
}

#[test]
fn test_ndcg_worst_ranking() {
    // All relevant docs at bottom
    let rels = vec![0.0, 0.0, 0.0, 2.0, 1.0];
    let score = ndcg_at_k(&rels, 5);
    assert!(score < 0.5, "Worst ranking should score low: {score}");
}

#[test]
fn test_ndcg_empty() {
    let rels: Vec<f64> = vec![];
    assert_eq!(ndcg_at_k(&rels, 10), 0.0);
}

#[test]
fn test_ndcg_no_relevant() {
    let rels = vec![0.0, 0.0, 0.0];
    assert_eq!(ndcg_at_k(&rels, 3), 0.0);
}

#[test]
fn test_mrr_first_position() {
    let rels = vec![1.0, 0.0, 0.0];
    assert_eq!(mrr(&rels, 1.0), 1.0);
}

#[test]
fn test_mrr_third_position() {
    let rels = vec![0.0, 0.0, 1.0, 0.0];
    assert!((mrr(&rels, 1.0) - 1.0/3.0).abs() < 1e-10);
}

#[test]
fn test_percentile_median() {
    let values: Vec<Duration> = (1..=100).map(|i| Duration::from_millis(i)).collect();
    let p50 = percentile(&values, 0.50);
    assert!((p50 - 50.0).abs() < 1.5, "p50 should be ~50ms: {p50}");
}

#[test]
fn test_percentile_p99() {
    let values: Vec<Duration> = (1..=100).map(|i| Duration::from_millis(i)).collect();
    let p99 = percentile(&values, 0.99);
    assert!(p99 >= 99.0, "p99 should be >=99ms: {p99}");
}

#[test]
fn test_cv_constant_values() {
    let values: Vec<Duration> = (0..10).map(|_| Duration::from_millis(50)).collect();
    assert_eq!(coefficient_of_variation(&values), 0.0);
}

#[test]
fn test_cv_variable_values() {
    let values = vec![Duration::from_millis(10), Duration::from_millis(100)];
    let cv = coefficient_of_variation(&values);
    assert!(cv > 0.5, "High variability should give high CV: {cv}");
}

#[test]
fn test_bootstrap_ci_narrow_for_tight_data() {
    let values: Vec<f64> = (0..100).map(|i| 50.0 + (i as f64 * 0.01)).collect();
    let (lo, hi) = bootstrap_ci(&values, 1000, 0.95);
    assert!((hi - lo) < 1.0, "Tight data should give narrow CI: [{lo}, {hi}]");
}

