```rust
#[proptest]
fn prop_ndcg_bounded(rels: Vec<f64>) {
    let filtered: Vec<f64> = rels.into_iter().filter(|r| r.is_finite() && *r >= 0.0).collect();
    if !filtered.is_empty() {
        let score = ndcg_at_k(&filtered, 10);
        assert!(score >= 0.0 && score <= 1.0, "NDCG must be in [0,1]: {score}");
    }
}

#[proptest]
fn prop_percentile_monotonic(p1: f64, p2: f64) {
    let p1 = p1.clamp(0.0, 1.0);
    let p2 = p2.clamp(0.0, 1.0);
    let values: Vec<Duration> = (1..=100).map(|i| Duration::from_millis(i)).collect();
    if p1 <= p2 {
        assert!(percentile(&values, p1) <= percentile(&values, p2));
    }
}
