### Archive Stats Structure
```rust
#[derive(Default, Clone, Debug)]
pub struct ArchiveStats {
    pub tweet_count: u64,
    pub like_count: u64,
    pub dm_count: u64,
    pub grok_count: u64,
    pub total_documents: u64,

    pub archive_size_bytes: u64,
    pub index_size_bytes: u64,
    pub database_size_bytes: u64,

    pub date_range_start: Option<DateTime<Utc>>,
    pub date_range_end: Option<DateTime<Utc>>,

    pub index_last_updated: Option<DateTime<Utc>>,
    pub index_doc_count: u64,
    pub embedding_count: u64,

    pub archive_path: PathBuf,
}

impl ArchiveStats {
    pub fn total_size_bytes(&self) -> u64 {
        self.archive_size_bytes + self.index_size_bytes + self.database_size_bytes
    }

    pub fn is_index_stale(&self) -> bool {
        self.index_doc_count < self.total_documents
    }

    pub fn index_coverage_pct(&self) -> f64 {
        if self.total_documents == 0 {
            return 100.0;
        }
        (self.index_doc_count as f64 / self.total_documents as f64) * 100.0
    }
}
