```rust
pub struct ReplStatusLine {
    archive_path: PathBuf,
    doc_count: usize,
    index_status: IndexStatus,
    theme: Theme,
}

impl ReplStatusLine {
    pub fn new(
        archive_path: PathBuf,
        doc_count: usize,
        index_status: IndexStatus,
        theme: &Theme,
    ) -> Self {
        Self {
            archive_path,
            doc_count,
            index_status,
            theme: theme.clone(),
        }
    }

    pub fn render(&self, output: &Output) -> String {
        if !output.is_styled() {
            let status = match self.index_status {
                IndexStatus::Ready => "ready",
                IndexStatus::Stale => "stale",
                IndexStatus::Missing => "missing",
            };
            return format!(
                "Archive: {} | {} docs | Index: {}",
                self.archive_path.file_name().unwrap_or_default().to_string_lossy(),
                self.doc_count,
                status
            );
        }

        let status_icon = match self.index_status {
            IndexStatus::Ready => format!("[{}]●[/]", self.theme.success),
            IndexStatus::Stale => format!("[{}]●[/]", self.theme.warning),
            IndexStatus::Missing => format!("[{}]●[/]", self.theme.error),
        };

        format!(
            "{} [{}]{}[/] | [{}]{} docs[/]",
            status_icon,
            self.theme.muted,
            self.archive_path.file_name().unwrap_or_default().to_string_lossy(),
            self.theme.info,
            self.doc_count
        )
    }
}
