### Search Term Extraction
```rust
use once_cell::sync::Lazy;
use regex::Regex;

/// Regex for extracting search terms (words, quoted phrases)
static TERM_REGEX: Lazy<Regex> = Lazy::new(|| {
    Regex::new(r#""([^"]+)"|(\S+)"#).expect("Invalid term regex")
});

/// Extract search terms from a query string
pub fn extract_terms(query: &str) -> Vec<String> {
    TERM_REGEX.captures_iter(query)
        .filter_map(|cap| {
            cap.get(1) // Quoted phrase
                .or(cap.get(2)) // Single word
                .map(|m| m.as_str().to_lowercase())
        })
        .filter(|term| {
            // Skip common operators and short words
            !matches!(term.as_str(), "and" | "or" | "not" | "the" | "a" | "an")
                && term.len() >= 2
        })
        .collect()
}
```

