```rust
use rich_rust::prelude::*;

pub struct SearchResultCard {
    doc_id: String,
    doc_type: String,
    content: String,
    score: f32,
    timestamp: Option<DateTime<Utc>>,
    highlight_terms: Vec<String>,
    max_content_length: usize,
}

impl SearchResultCard {
    pub fn new() -> Self {
        Self {
            doc_id: String::new(),
            doc_type: String::new(),
            content: String::new(),
            score: 0.0,
            timestamp: None,
            highlight_terms: vec![],
            max_content_length: 280, // Default to tweet length
        }
    }

    pub fn doc_id(mut self, id: impl Into<String>) -> Self {
        self.doc_id = id.into();
        self
    }

    pub fn doc_type(mut self, dtype: impl Into<String>) -> Self {
        self.doc_type = dtype.into();
        self
    }

    pub fn content(mut self, text: impl Into<String>) -> Self {
        self.content = text.into();
        self
    }

    pub fn score(mut self, score: f32) -> Self {
        self.score = score;
        self
    }

    pub fn timestamp(mut self, ts: DateTime<Utc>) -> Self {
        self.timestamp = Some(ts);
        self
    }

    pub fn highlight_terms(mut self, terms: Vec<String>) -> Self {
        self.highlight_terms = terms;
        self
    }

    pub fn max_content_length(mut self, len: usize) -> Self {
        self.max_content_length = len;
        self
    }

    /// Truncate content with ellipsis if too long
    fn truncate_content(&self) -> String {
        if self.content.len() <= self.max_content_length {
            return self.content.clone();
        }

        // Try to break at word boundary
        let truncated = &self.content[..self.max_content_length];
        if let Some(last_space) = truncated.rfind(' ') {
            format!("{}…", &truncated[..last_space])
        } else {
            format!("{}…", truncated)
        }
    }

    /// Apply highlighting to content
    fn highlight_content(&self, content: &str, theme: &Theme) -> String {
        let mut result = content.to_string();

        for term in &self.highlight_terms {
            let pattern = regex::Regex::new(&format!(r"(?i)\b{}\b", regex::escape(term)))
                .unwrap_or_else(|_| regex::Regex::new(r"(?!)").unwrap());
            result = pattern.replace_all(&result, &format!(
                "[bold {}]$0[/]", theme.highlight
            )).into();
        }

        result
    }

    pub fn render(&self, output: &Output) {
        if !output.is_styled() {
            self.render_plain(output);
            return;
        }

        self.render_styled(output);
    }

    fn render_styled(&self, output: &Output) {
        let theme = &output.theme;

        // Score badge
        let score_pct = (self.score * 100.0) as u32;
        let score_style = theme.score_style(self.score);
        let score_badge = format!("[{}]{}%[/]", score_style, score_pct);

        // Doc type badge
        let type_color = match self.doc_type.as_str() {
            "tweet" => theme.primary,
            "like" => theme.error,      // Red for hearts
            "dm" => theme.secondary,    // Purple for DMs
            "grok" => theme.accent,     // Orange for Grok
            _ => theme.muted,
        };
        let type_badge = format!("[{} bold]{}[/]", type_color, self.doc_type.to_uppercase());

        // Timestamp
        let time_str = self.timestamp
            .map(|ts| ts.format("%Y-%m-%d %H:%M").to_string())
            .unwrap_or_else(|| "—".to_string());
        let time_display = format!("[{}]{}[/]", theme.timestamp, time_str);

        // Header line
        let header = format!("{} {} • {} • [{}]{}[/]", 
            score_badge, type_badge, time_display, theme.muted, self.doc_id);

        // Content with highlighting and truncation
        let content = self.truncate_content();
        let highlighted = self.highlight_content(&content, theme);

        // Build panel
        let panel_content = format!("{}\n\n{}", header, highlighted);
        let panel = Panel::from_text(&panel_content)
            .border_style(theme.border);

        output.print_renderable(&panel);
    }

    fn render_plain(&self, output: &Output) {
        let score_pct = (self.score * 100.0) as u32;
        let time_str = self.timestamp
            .map(|ts| ts.format("%Y-%m-%d %H:%M").to_string())
            .unwrap_or_else(|| "—".to_string());

        println!("{}% | {} | {} | {}", score_pct, self.doc_type, time_str, self.doc_id);
        println!("{}", self.truncate_content());
        println!("---");
    }

    /// Render to string (for testing)
    pub fn render_to_string(&self, output: &Output) -> String {
        // Use a capture mechanism
        // This is a simplified version - real impl would capture stdout
        if output.is_styled() {
            format!(
                "{}% {} {} {}",
                (self.score * 100.0) as u32,
                self.doc_type,
                self.timestamp.map(|t| t.to_string()).unwrap_or_default(),
                self.content
            )
        } else {
            format!(
                "{}% | {} | {}",
                (self.score * 100.0) as u32,
                self.doc_type,
                self.truncate_content()
            )
        }
    }
}
